export function isDateSelectable(date: NgbDate | null | undefined, state: DatepickerViewModel) {
	const { minDate, maxDate, disabled, markDisabled } = state;
	return !(
		date === null ||
		date === undefined ||
		disabled ||
		(markDisabled && markDisabled(date, { year: date.year, month: date.month })) ||
		(minDate && date.before(minDate)) ||
		(maxDate && date.after(maxDate))
	);
}

function toActionName<EventName extends string>(
  eventName: EventName
): ActionName<EventName> {
  return eventName
    .trim()
    .split(' ')
    .map((word, i) => (i === 0 ? uncapitalize(word) : capitalize(word)))
    .join('') as ActionName<EventName>;
}

function toActionType<Source extends string, EventName extends string>(
  source: Source,
  eventName: EventName
): `[${Source}] ${EventName}` {
  return `[${source}] ${eventName}`;
}

private getSelectAllValue(options: any[]) {
  if (!this.selectAllValue || options !== this.selectAllValue.options) {
    const flatOptions: any[] = [];
    options.forEach((o) => (o.group ? flatOptions.push(...o.group) : flatOptions.push(o)));

    this.selectAllValue = {
      options,
      value: flatOptions.filter((o) => !o.disabled).map((o) => o.value),
    };
  }

  return this.selectAllValue.value;
}

destroy(): void {
  if (!this._destroyed) {
    this._destroyed = true;
    this._resetDomPlayerState();
    this._onFinish();
    if (this._specialStyles) {
      this._specialStyles.destroy();
    }
    this._onDestroyFns.forEach((fn) => fn());
    this._onDestroyFns = [];
  }
}

export function isHiddenField(field: FormlyFieldConfig) {
  const isHidden = (f: FormlyFieldConfig) => f.hide || f.expressions?.hide || f.hideExpression;
  let setDefaultValue = !field.resetOnHide || !isHidden(field);
  if (!isHidden(field) && field.resetOnHide) {
    let parent = field.parent;
    while (parent && !isHidden(parent)) {
      parent = parent.parent;
    }
    setDefaultValue = !parent || !isHidden(parent);
  }

  return !setDefaultValue;
}

export function d3InjectorTreeLinkModifier(link: SvgD3Link<InjectorTreeNode>) {
  link
    .attr('hidden', (node: InjectorTreeD3Node) => {
      const parentId = node.parent?.data.injector.id;
      return parentId === 'N/A' ? 'true' : null;
    })
    .attr('data-id', (node: InjectorTreeD3Node) => {
      const from = node.data.injector.id;
      const to = node.parent?.data.injector.id;

      if (from && to) {
        return `${from}-to-${to}`;
      }
      return '';
    });
}

